                  to={item.path}
                  className="block px-3 py-3 text-base font-medium text-gray-300 hover:bg-white/5 hover:text-yellow-500 rounded-lg uppercase tracking-wider transition-all duration-300 ease-out"
                >
                  {item.name}
                </Link>
              )}
            </div>
          ))}
        </div>
      </div>
    </nav>
  );
