                initial="hidden"
                whileInView="visible"
                viewport={{ once: true }}
                variants={{
                  hidden: { opacity: 0 },
                  visible: { opacity: 1, transition: { staggerChildren: 0.2 } }
                }}
              >
                <ul className="space-y-4 mb-10">
                  {['Tekla Certified', '24/7 Support', 'Cost Efficient'].map((item, i) => (
                    <motion.li
                      key={i}
                      variants={{
                        hidden: { opacity: 0, x: -20 },
                        visible: { opacity: 1, x: 0, transition: { duration: 0.8 } }
                      }}
                      className="flex items-center space-x-3 text-white font-bold"
                    >
                      <div className="w-6 h-6 rounded-full bg-yellow-500/20 flex items-center justify-center text-yellow-500 border border-yellow-500/30">
                        <CheckCircle2 size={14} strokeWidth={4} />
                      </div>
                      <span>{item}</span>
                    </motion.li>
                  ))}
                </ul>
              </motion.div>
            </div>
          </div>
        </div>
      </section>

      {/* --- 4. CORE VALUES --- */}
      <section className="py-48 bg-slate-950 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-slate-900 to-transparent pointer-events-none z-10"></div>
        <div className="absolute bottom-0 left-0 w-full h-32 bg-gradient-to-t from-slate-900 to-transparent pointer-events-none z-10"></div>
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-yellow-500/5 rounded-full blur-3xl pointer-events-none z-0"></div>

        <div className="max-w-7xl mx-auto px-6 lg:px-12 relative z-10">
          <div className="text-center mb-20">
            <Reveal>
              <h2 className="text-3xl md:text-5xl font-bold text-white mb-6">Our Core Values</h2>
              <div className="w-24 h-1.5 bg-gradient-to-r from-yellow-400 to-yellow-600 mx-auto rounded-full"></div>
            </Reveal>
          </div>

          <motion.div
            className="grid md:grid-cols-2 lg:grid-cols-4 gap-6"
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-50px" }}
            variants={{
              hidden: { opacity: 0 },
              visible: { opacity: 1, transition: { staggerChildren: 0.2 } }
            }}
          >
            {values.map((val, i) => (
              <motion.div
                key={i}
                variants={{
                  hidden: { opacity: 0, y: 40 },
                  visible: { opacity: 1, y: 0, transition: { duration: 0.9, ease: "easeOut" } }
                }}
              >
                <div className="group h-full bg-slate-900/40 backdrop-blur-sm border border-white/5 p-8 rounded-2xl hover:bg-slate-800/60 hover:border-yellow-500/50 hover:-translate-y-2 transition-all duration-300">
                  <div className="w-14 h-14 bg-slate-900 rounded-xl flex items-center justify-center text-yellow-500 mb-6 group-hover:scale-110 transition-transform shadow-lg shadow-black/50 border border-white/10">
                    <val.icon className="w-7 h-7" />
                  </div>
                  <h3 className="text-xl font-bold text-white mb-4">{val.title}</h3>
                  <p className="text-slate-400 text-sm leading-relaxed border-t border-white/5 pt-4">
                    {val.desc}
                  </p>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* --- 5. INTERACTIVE PROTRACTOR TIMELINE --- */}
      <section
        className="py-20 md:py-32 relative overflow-hidden bg-slate-900/50"
        onMouseEnter={() => setIsPaused(true)}
        onMouseLeave={() => setIsPaused(false)}
      >
        <div className="max-w-7xl mx-auto px-4 relative z-10">

          <motion.div
            initial={{ opacity: 0, y: 30 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ duration: 1.0 }}
            className="text-center mb-8 md:mb-16"
          >
            <span className="text-yellow-500 font-bold tracking-widest uppercase text-sm">Our Legacy</span>
            <h2 className="text-3xl md:text-4xl font-bold text-white mt-2">Engineering History</h2>
          </motion.div>

          {/* SVG PROTRACTOR CONTAINER */}
          <div className="relative w-full max-w-4xl mx-auto aspect-[2/1] select-none">

            <svg viewBox="0 0 1000 500" className="w-full h-full overflow-visible">

              {/* 1. OUTER ARC RINGS */}
              <path d="M 100 500 A 400 400 0 0 1 900 500" fill="none" stroke="#475569" strokeWidth="2" />
              <path d="M 50 500 A 450 450 0 0 1 950 500" fill="none" stroke="#334155" strokeWidth="1" strokeDasharray="6 6" />

              {/* 2. TICKS & CONVERGING LINES */}
              {Array.from({ length: 181 }).map((_, i) => {
                const angleDeg = 180 - i;
                const angleRad = (angleDeg * Math.PI) / 180;

                // MATH: Coordinate Calculations
                const cx = 500;
                const cy = 500;

                // Active State Logic
                const isMajor = i % 10 === 0;
                // FIX: Use the shared fixedAngles array
                const activeAngle = fixedAngles[activeItem];
                const isActiveLine = isMajor && (angleDeg === activeAngle);

                // Coordinates for Line Drawing
                const tickInnerR = 380;
                const tickOuterR = isMajor ? 415 : 395;
                const tx1 = cx + tickInnerR * Math.cos(angleRad);
                const ty1 = cy - tickInnerR * Math.sin(angleRad);
                const tx2 = cx + tickOuterR * Math.cos(angleRad);
                const ty2 = cy - tickOuterR * Math.sin(angleRad);

                const rayStartR = 0;
                const rayEndR = 370;
                const rx1 = cx + rayStartR * Math.cos(angleRad);
                const ry1 = cy - rayStartR * Math.sin(angleRad);
                const rx2 = cx + rayEndR * Math.cos(angleRad);
                const ry2 = cy - rayEndR * Math.sin(angleRad);

                return (
                  <g key={i}>
                    {/* Ticks */}
                    <line x1={tx1} y1={ty1} x2={tx2} y2={ty2}
                      stroke={isMajor ? "#94a3b8" : "#475569"}
                      strokeWidth={isMajor ? 2 : 1}
                    />

                    {/* Rays (Connecting Lines) */}
                    {isMajor && (
                      <line x1={rx1} y1={ry1} x2={rx2} y2={ry2}
                        stroke={isActiveLine ? "#EAB308" : "#1e293b"}
                        strokeWidth={isActiveLine ? "2" : "1"}
                        className="transition-colors duration-500 ease-in-out"
                        style={{ opacity: isActiveLine ? 1 : 0.5 }}
                      />
                    )}
                  </g>
                );
              })}

              {/* 3. HISTORY NODES */}
              {history.map((item, index) => {
                const currentDeg = fixedAngles[index];
                const angleRad = (currentDeg * Math.PI) / 180;

                const r = 400;
                const cx = 500;
                const cy = 500;

                const x = cx + r * Math.cos(angleRad);
                const y = cy - r * Math.sin(angleRad);
                const isActive = activeItem === index;

                return (
                  <g
                    key={index}
                    onClick={() => { setActiveItem(index); setIsPaused(true); }}
                    onMouseEnter={() => { setActiveItem(index); setIsPaused(true); }}
                    className="cursor-pointer group"
                  >
                    {isActive && (
                      <circle cx={x} cy={y} r={10} fill="#eab308" opacity="0.4">
                        <animate attributeName="r" from="10" to="28" dur="1.5s" begin="0s" repeatCount="indefinite" />
                        <animate attributeName="opacity" from="0.4" to="0" dur="1.5s" begin="0s" repeatCount="indefinite" />
                      </circle>
                    )}
                    <circle cx={x} cy={y} r={isActive ? 10 : 6} fill={isActive ? "#eab308" : "#1e293b"} stroke={isActive ? "#fff" : "#64748b"} strokeWidth="2" className="transition-all duration-300" />
                    <text x={x} y={y - 25} textAnchor="middle" className={`text-sm font-bold transition-all duration-300 select-none ${isActive ? 'fill-yellow-500 text-xl' : 'fill-slate-500'}`}>
                      {item.year}
                    </text>
                  </g>
                );
              })}

              {/* 4. CENTRAL CARD */}
              <foreignObject x="250" y="220" width="500" height="280">
                <div className="w-full h-full flex flex-col items-center justify-end text-center p-4">
                  <div className="bg-slate-800 border border-white/10 shadow-2xl p-8 rounded-2xl transform transition-all duration-500 w-full h-full flex flex-col justify-center relative overflow-hidden z-20">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500 to-transparent"></div>
                    <div key={activeItem} className="animate-fade-in-up">
                      <h3 className="text-3xl font-bold text-white mb-3">{history[activeItem].year}</h3>
                      <h4 className="text-xl font-semibold text-yellow-500 mb-2">{history[activeItem].title}</h4>
                      <p className="text-slate-400 text-sm leading-relaxed">{history[activeItem].desc}</p>
                    </div>
                  </div>
                </div>
              </foreignObject>

            </svg>

            {/* NAVIGATION ARROWS */}
            <button
              onClick={handlePrev}
              className="absolute left-[25%] top-[72%] -translate-y-1/2 -translate-x-1/2 p-3 rounded-full bg-slate-800 shadow-lg border border-white/10 text-slate-400 hover:text-yellow-500 hover:border-yellow-500 transition-all z-30 group"
              aria-label="Previous Year"
            >
              <ChevronLeft className="w-6 h-6 group-hover:-translate-x-0.5 transition-transform" />
            </button>
            <button
              onClick={handleNext}
              className="absolute left-[75%] top-[72%] -translate-y-1/2 -translate-x-1/2 p-3 rounded-full bg-slate-800 shadow-lg border border-white/10 text-slate-400 hover:text-yellow-500 hover:border-yellow-500 transition-all z-30 group"
              aria-label="Next Year"
            >
              <ChevronRight className="w-6 h-6 group-hover:translate-x-0.5 transition-transform" />
            </button>

          </div>
        </div>
      </section>

      {/* --- 6. CTA SECTION --- */}
      <section className="py-24 bg-gradient-to-br from-slate-900 to-slate-950 text-center relative overflow-hidden">
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 1.0 }}
          className="relative z-10 px-6"
        >
          <h2 className="text-4xl md:text-5xl font-bold text-white mb-8">Want to be part of our next chapter?</h2>
          <p className="text-slate-400 mb-8 text-lg max-w-2xl mx-auto">
            Whether you need engineering services or want to join our growing team, we'd love to hear from you.
          </p>
          <Link to="/contact" className="group inline-flex items-center px-8 py-4 bg-yellow-500 text-slate-900 font-bold rounded-full hover:bg-white transition-all shadow-[0_0_40px_-10px_rgba(234,179,8,0.6)] hover:shadow-white/20 hover:scale-105">
            Get A Quote <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
          </Link>
        </motion.div>
      </section>

    </div>
  );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import { MapPin, Phone, Mail, Upload, FileText, Send, CheckCircle2 } from 'lucide-react';
import Footer from '../components/Footer';

// Animation Variants - Added 'as const' to fix TypeScript errors
const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1,
      delayChildren: 0.2
    }
  }
} as const;

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.5, ease: "easeOut" }
  }
} as const;

export default function Contact() {
  const [dragActive, setDragActive] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    company: '',
    service: 'Structural Steel Detailing',
    details: ''
  });
  const [isLoading, setIsLoading] = useState(false);
  const [statusMessage, setStatusMessage] = useState({ type: '', text: '' });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setStatusMessage({ type: '', text: '' });

    try {
      let file_content = null;
      let file_name = null;

      if (selectedFile) {
        file_content = await fileToBase64(selectedFile);
        file_name = selectedFile.name;
      }

      const response = await fetch('/api/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...formData,
          file_name,
          file_content
        }),
      });

      if (response.ok) {
        setStatusMessage({ type: 'success', text: 'Thank you! Your inquiry has been sent.' });
        setFormData({
          firstName: '',
          lastName: '',
          email: '',
          company: '',
          service: 'Structural Steel Detailing',
          details: ''
        });
        setSelectedFile(null);
      } else {
        const errorData = await response.json();
        throw new Error(errorData.error?.message || 'Failed to send');
      }
    } catch (error) {
      setStatusMessage({ type: 'error', text: 'Failed to send the request. Please try again.' });
    } finally {
      setIsLoading(false);
    }
  };

  // --- File Upload Logic ---
  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setSelectedFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    e.preventDefault();
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-white pt-24 pb-0 selection:bg-yellow-500 selection:text-black overflow-hidden relative flex flex-col">

      {/* --- BACKGROUND ENHANCEMENTS --- */}
      {/* 1. Base Grid */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.03]"
        style={{ backgroundImage: 'linear-gradient(#ffffff 1px, transparent 1px), linear-gradient(90deg, #ffffff 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
      </div>

      {/* 2. Animated Glow Orbs */}
      <motion.div
        animate={{ opacity: [0.3, 0.6, 0.3], scale: [1, 1.2, 1] }}
        transition={{ duration: 8, repeat: Infinity, ease: "easeInOut" }}
        className="fixed top-0 left-[-10%] w-[600px] h-[600px] bg-yellow-500/5 rounded-full blur-[120px] pointer-events-none"
      />
      <motion.div
        animate={{ opacity: [0.2, 0.5, 0.2], scale: [1, 1.1, 1] }}
        transition={{ duration: 10, repeat: Infinity, ease: "easeInOut", delay: 1 }}
        className="fixed bottom-0 right-[-10%] w-[600px] h-[600px] bg-slate-500/10 rounded-full blur-[120px] pointer-events-none"
      />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10 flex-grow mb-20">

        {/* --- HEADER ANIMATION --- */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: "circOut" }}
          className="text-center mb-16"
        >
          <motion.h1
            className="text-4xl md:text-6xl font-bold text-white mb-6"
            initial={{ letterSpacing: "-0.05em" }}
            animate={{ letterSpacing: "0em" }}
            transition={{ duration: 1, ease: "easeOut" }}
          >
            Start Your <span className="text-yellow-500 inline-block">Project</span>
          </motion.h1>
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 1 }}
            className="text-xl text-gray-400 max-w-2xl mx-auto"
          >
            Ready to optimize your structure? Submit your architectural plans or details below, and our engineering team will provide a comprehensive technical proposal.
          </motion.p>
        </motion.div>

        <div className="grid lg:grid-cols-12 gap-12 items-start">

          {/* --- LEFT COLUMN: Contact Info --- */}
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.3, duration: 0.6 }}
            className="lg:col-span-5 space-y-8"
          >
            {/* Info Card */}
            <div className="bg-slate-800/50 backdrop-blur-md border border-white/10 p-8 rounded-sm shadow-xl">
              <h3 className="text-2xl font-bold text-white mb-6">Global Operations</h3>

              <div className="space-y-8">
                {/* Address */}
                <div className="flex items-start gap-4 group">
                  <div className="p-3 bg-yellow-500/10 rounded-sm border border-yellow-500/20 group-hover:bg-yellow-500/20 transition-colors">
                    <MapPin className="h-6 w-6 text-yellow-500" />
                  </div>
                  <div>
                    <span className="block text-sm font-bold text-slate-300 uppercase tracking-wider mb-1">Headquarters (Philippines)</span>
                    <p className="text-gray-400 leading-relaxed font-mono text-sm">
                      6A T. Bugallon St.<br />
                      Marikina Heights, Marikina City<br />
                      Philippines 1810
                    </p>
                  </div>
                </div>

                {/* Phone */}
                <div className="flex items-start gap-4 group">
                  <div className="p-3 bg-yellow-500/10 rounded-sm border border-yellow-500/20 group-hover:bg-yellow-500/20 transition-colors">
                    <Phone className="h-6 w-6 text-yellow-500" />
                  </div>
                  <div>
                    <span className="block text-sm font-bold text-slate-300 uppercase tracking-wider mb-1">Direct Lines</span>
                    <div className="space-y-1">
                      <p className="text-gray-400 font-mono text-sm flex items-center gap-2">
                        <span className="text-xs bg-slate-700 px-1 rounded text-white">PH</span> (+63) 962 664 0660
                      </p>
                      <p className="text-gray-400 font-mono text-sm flex items-center gap-2">
                        <span className="text-xs bg-slate-700 px-1 rounded text-white">CA</span>  +1  (584) 447 3416
                      </p>
                    </div>
                  </div>
                </div>

                {/* Email */}
                <div className="flex items-start gap-4 group">
                  <div className="p-3 bg-yellow-500/10 rounded-sm border border-yellow-500/20 group-hover:bg-yellow-500/20 transition-colors">
                    <Mail className="h-6 w-6 text-yellow-500" />
                  </div>
                  <div>
                    <span className="block text-sm font-bold text-slate-300 uppercase tracking-wider mb-1">Project Inquiries</span>
                    <p className="text-gray-400 font-mono text-sm">globalbim.ph@gmail.com</p>
                  </div>
                </div>
              </div>
            </div>

            {/* Trust Badges */}
            <div className="p-6 border border-dashed border-white/10 rounded-sm bg-white/[0.02]">
              <h4 className="text-sm font-bold text-white mb-4">WHY PARTNER WITH US?</h4>
              <ul className="space-y-3">
                {[
                  'AISC & NISD Compliant Standards',
                  'Turnaround Time Guarantee',
                  'Senior Engineering Oversight',
                  'Seamless BIM Integration'
                ].map((item, i) => (
                  <li key={i} className="flex items-center gap-3 text-sm text-gray-400">
                    <CheckCircle2 className="w-4 h-4 text-yellow-500" />
                    {item}
                  </li>
                ))}
              </ul>
            </div>
          </motion.div>

          {/* --- RIGHT COLUMN: The "Proposal" Form --- */}
          <motion.div
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: 0.5, duration: 0.6 }}
            className="lg:col-span-7"
          >
            <form onSubmit={handleSubmit} className="bg-slate-800 p-8 md:p-10 rounded-sm border-t-4 border-yellow-500 shadow-2xl relative overflow-hidden">
              {/* Form Header */}
              <div className="flex justify-between items-start mb-8 border-b border-white/10 pb-6">
                <div>
                  <h3 className="text-2xl font-bold text-white">Project Brief</h3>
                  <p className="text-slate-400 text-sm mt-1">Submit your requirements for a technical review.</p>
                </div>
              </div>

              {/* Status Message */}
              {statusMessage.text && (
                <div className={`mb-6 p-4 rounded-sm text-sm font-medium border ${statusMessage.type === 'success' ? 'bg-green-500/10 border-green-500/20 text-green-400' : 'bg-red-500/10 border-red-500/20 text-red-400'}`}>
                  {statusMessage.text}
                </div>
              )}

              {/* Form Fields with Staggered Animation */}
              <motion.div
                className="space-y-6"
                variants={containerVariants}
                initial="hidden"
                animate="visible"
              >
                {/* 1. Split Name Fields */}
                <div className="grid md:grid-cols-2 gap-6">
                  <motion.div variants={itemVariants}>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">First Name</label>
                    <input type="text" name="firstName" value={formData.firstName} onChange={handleInputChange} required className="w-full bg-slate-900 border border-white/10 text-white p-3 rounded-sm focus:outline-none focus:border-yellow-500 transition-colors" placeholder="John" />
                  </motion.div>
                  <motion.div variants={itemVariants}>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Last Name</label>
                    <input type="text" name="lastName" value={formData.lastName} onChange={handleInputChange} required className="w-full bg-slate-900 border border-white/10 text-white p-3 rounded-sm focus:outline-none focus:border-yellow-500 transition-colors" placeholder="Doe" />
                  </motion.div>
                </div>

                {/* 2. Email & Company */}
                <div className="grid md:grid-cols-2 gap-6">
                  <motion.div variants={itemVariants}>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Work Email</label>
                    <input type="email" name="email" value={formData.email} onChange={handleInputChange} required className="w-full bg-slate-900 border border-white/10 text-white p-3 rounded-sm focus:outline-none focus:border-yellow-500 transition-colors" placeholder="john@company.com" />
                  </motion.div>
                  <motion.div variants={itemVariants}>
                    <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Company / Organization</label>
                    <input type="text" name="company" value={formData.company} onChange={handleInputChange} required className="w-full bg-slate-900 border border-white/10 text-white p-3 rounded-sm focus:outline-none focus:border-yellow-500 transition-colors" placeholder="Construction Co." />
                  </motion.div>
                </div>

                {/* 3. Service Selector */}
                <motion.div variants={itemVariants}>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Service Required</label>
                  <div className="relative">
                    <select name="service" value={formData.service} onChange={handleInputChange} className="w-full bg-slate-900 border border-white/10 text-white p-3 rounded-sm focus:outline-none focus:border-yellow-500 transition-colors appearance-none cursor-pointer">
                      <option>Structural Steel Detailing</option>
                      <option>Pre-Engineered Buildings (PEB)</option>
                      <option>Steel Design & Analysis</option>
                      <option>BIM Consulting</option>
                      <option>Other / General Inquiry</option>
                    </select>
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">Γû╝</div>
