const getPointOnArc = (angleInDegrees: number, radius: number) => {
  const cx = 500;
  const cy = 500;
  const angleInRadians = (angleInDegrees * Math.PI) / 180;
  return {
    x: cx + radius * Math.cos(angleInRadians),
    y: cy - radius * Math.sin(angleInRadians)
  };
};

const regionMappings: Record<string, { top: string, left: string, isHQ?: boolean, iconImg: string }> = {
  "Metro Manila, Philippines": { top: '51.6%', left: '74.5%', isHQ: true, iconImg: industrialReal },
  "United Arab Emirates": { top: '48.5%', left: '60.5%', iconImg: commercialReal },
  "Saudi Arabia": { top: '47.0%', left: '57.0%', iconImg: industrialReal },
  "Qatar": { top: '48.0%', left: '59.0%', iconImg: commercialReal },
  "Senegal": { top: '53.3%', left: '43.5%', iconImg: infrastructureReal },
  "Peru": { top: '61.0%', left: '30.0%', iconImg: infrastructureReal },
  "United States": { top: '33.0%', left: '24.0%', iconImg: warehouseReal },
  "Greece": { top: '38.0%', left: '52.0%', iconImg: commercialReal },
  "Yemen": { top: '51.6%', left: '58.9%', iconImg: industrialReal }
};

const mapLocationToRegion = (location: string) => {
  const loc = location.toLowerCase();
  if (loc.includes('dubai') || loc.includes('abu dhabi')) return "United Arab Emirates";
  if (loc.includes('saudi') || loc.includes('riyadh') || loc.includes('jeddah') || loc.includes('tabuk')) return "Saudi Arabia";
  if (loc.includes('qatar')) return "Qatar";
  if (loc.includes('senegal')) return "Senegal";
  if (loc.includes('peru')) return "Peru";
  if (loc.includes('michigan') || loc.includes('texas')) return "United States";
  if (loc.includes('athens') || loc.includes('greece')) return "Greece";
  if (loc.includes('yemen')) return "Yemen";
  if (loc.includes('philippines') || loc.includes('manila') || loc.includes('marikina')) return "Metro Manila, Philippines";
  return "Unknown";
};

// Seed random years between 2012 and 2024
const getRandomYear = (id: string) => {
  let hash = 0;
  for (let i = 0; i < id.length; i++) hash = id.charCodeAt(i) + ((hash << 5) - hash);
  return 2012 + Math.abs(hash) % 13;
};

