const Reveal = ({ children, delay = '', direction = 'up', className = '' }: { children: React.ReactNode; delay?: string; direction?: 'up' | 'left' | 'right'; className?: string; }) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => { if (entry.isIntersecting) { setIsVisible(true); observer.unobserve(entry.target); } }, { threshold: 0.15 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  const getAnimationClass = () => {
    switch (direction) {
      case 'left': return 'animate-slide-in-left';
      case 'right': return 'animate-slide-in-right';
      default: return 'animate-slide-up';
    }
  };

  return <div ref={ref} className={`${isVisible ? `${getAnimationClass()} ${delay}` : 'opacity-0 translate-y-8'} ${className}`}>{children}</div>;
};

const CountUpComponent = ({ end, suffix = '' }: { end: number; suffix?: string }) => {
  const [count, setCount] = useState(0);
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => { if (entry.isIntersecting) setIsVisible(true); }, { threshold: 0.5 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (!isVisible) return;
    let start = 0;
    const increment = end / (2000 / 16);
    const timer = setInterval(() => {
      start += increment;
      if (start >= end) { setCount(end); clearInterval(timer); } else { setCount(Math.floor(start)); }
    }, 16);
    return () => clearInterval(timer);
  }, [end, isVisible]);

  return <span ref={ref}>{count}{suffix}</span>;
};

