                      >
                        {/* Pulse Animation - At the bottom (ground level) */}
                        <div className="absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-1/2 pointer-events-none">
                          <div className={`w-8 h-8 rounded-full ${pin.isHQ ? 'bg-yellow-500' : 'bg-blue-500'} opacity-20 animate-ping`}></div>
                        </div>

                        {/* The MapPin Icon */}
                        <MapPin
                          className={`w-6 h-6 transition-all duration-300 drop-shadow-lg ${pin.isHQ
                            ? 'text-yellow-500 fill-yellow-500/30'
                            : 'text-blue-400 fill-slate-900/80'
                            } ${isHovered ? 'scale-125 -translate-y-2 text-white fill-yellow-500' : ''}`}
                          strokeWidth={2}
                        />

                        {/* --- RICH HOVER CARD --- */}
                        <AnimatePresence>
                          {isHovered && (
                            <motion.div
                              initial={{ opacity: 0, y: 10, scale: 0.95 }}
                              animate={{ opacity: 1, y: 0, scale: 1 }}
                              exit={{ opacity: 0, y: 10, scale: 0.95 }}
                              transition={{ duration: 0.2 }}
                              // Added pointer-events-auto to allow scrolling inside the card
                              className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 w-72 bg-slate-900/95 border border-yellow-500/30 p-4 rounded-lg shadow-2xl backdrop-blur-md pointer-events-auto z-50 flex flex-col gap-3"
                              onMouseEnter={() => setHoveredProject(pin)}
                              onMouseLeave={() => setHoveredProject(null)}
                            >
                              {/* Header Area */}
                              <div className="flex items-center justify-between border-b border-white/10 pb-2">
                                <h4 className="text-sm font-bold text-white leading-tight flex items-center gap-1.5">
                                  <MapPin className="w-3.5 h-3.5 text-yellow-500 shrink-0" />
                                  {pin.region}
                                </h4>
                                <span className="text-[10px] font-bold text-yellow-500 uppercase tracking-wider bg-black/50 backdrop-blur-sm px-1.5 py-0.5 rounded border border-yellow-500/20 shrink-0">
                                  {pin.projects.length} Project{pin.projects.length > 1 ? 's' : ''}
                                </span>
                              </div>

                              {/* Scrollable interior list */}
                              <div className="max-h-40 overflow-y-auto custom-scrollbar pr-1 space-y-2">
                                {pin.projects.map((proj: any) => (
                                  <div
                                    key={proj.id}
                                    className="bg-slate-800/50 px-2 py-1.5 rounded border border-white/5 hover:border-yellow-500/50 hover:bg-slate-800 transition-colors cursor-pointer group/item"
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setActiveProject(proj);
                                    }}
                                  >
                                    <div className="text-[10px] text-slate-300 font-medium leading-tight mb-1 group-hover/item:text-white transition-colors">{proj.title}</div>
                                    <div className="flex justify-between items-center">
                                      <span className="text-[9px] text-slate-500 uppercase tracking-widest">{proj.location}</span>
                                      <span className="text-[10px] text-yellow-500 font-mono font-bold">{proj.year}</span>
                                    </div>
                                  </div>
                                ))}
                              </div>

                              {/* Triangle Indicator */}
                              <div className="absolute top-full left-1/2 -translate-x-1/2 -mt-[1px] pointer-events-none">
                                <div className="w-3 h-3 bg-slate-900 border-r border-b border-yellow-500/30 rotate-45 transform"></div>
                              </div>
                            </motion.div>
                          )}
                        </AnimatePresence>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </Reveal>
        </div>
      </section>

      {/* --- CLICK PROJECT MODAL (RESTORED) --- */}
      <AnimatePresence>
        {activeProject && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4"
            onClick={() => setActiveProject(null)}
          >
            <motion.div
              initial={{ scale: 0.95, opacity: 0, y: 20 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.95, opacity: 0, y: 20 }}
              transition={{ type: "spring", damping: 25, stiffness: 300 }}
              className="bg-slate-900 border-t-[3px] border-t-yellow-500 border-x border-b border-white/10 rounded-xl max-w-2xl w-full p-8 md:p-12 shadow-2xl relative overflow-hidden"
              onClick={(e) => e.stopPropagation()}
            >
              {/* Decorative Background Elements */}
              <div className="absolute top-0 right-0 -mt-20 -mr-20 w-64 h-64 bg-yellow-500/5 rounded-full blur-3xl pointer-events-none"></div>

              {/* Close Button */}
              <button
                onClick={() => setActiveProject(null)}
                className="absolute top-6 right-6 p-2 bg-slate-800 hover:bg-slate-700 text-white rounded-full transition-colors border border-white/5 z-10"
              >
                <X className="w-5 h-5" />
              </button>

              <div className="relative z-10 flex flex-col items-start text-left">
                {/* Headers */}
                <div className="flex items-center gap-3 mb-6">
                  <span className="bg-yellow-500/10 text-yellow-500 border border-yellow-500/20 px-3 py-1 rounded font-mono text-xs tracking-widest uppercase">
                    {activeProject.type || activeProject.category}
                  </span>
                  {activeProject.isHQ && (
                    <span className="bg-blue-500/10 text-blue-400 border border-blue-500/20 px-3 py-1 rounded font-mono text-xs tracking-widest uppercase">
                      HQ
                    </span>
                  )}
                </div>

                <h3 className="text-3xl md:text-5xl font-bold text-white mb-4 leading-tight tracking-tight">
                  {activeProject.name || activeProject.title}
                </h3>

                <div className="flex items-center text-gray-400 text-lg md:text-xl mb-8 font-light">
                  <MapPin className="w-5 h-5 mr-3 text-yellow-500" />
                  {activeProject.location}
                </div>

                {/* Scope Frame */}
                <div className="w-full bg-slate-800/50 rounded-lg p-6 border border-white/5 shadow-inner">
                  <div className="text-xs text-slate-500 uppercase tracking-widest mb-4 font-bold flex items-center gap-2">
                    <Layers className="w-4 h-4 text-slate-600" /> Project Scope
                  </div>
                  <p className="text-gray-300 leading-relaxed text-base md:text-lg">
                    {activeProject.description}
                  </p>
                </div>

                {/* Footer Meta */}
                <div className="mt-8 w-full flex justify-end">
                  <div className="text-[10px] text-slate-600 font-mono tracking-widest uppercase bg-slate-800/80 px-3 py-1.5 rounded border border-white/5">
                    Map Region: {activeProject.coords || 'N/A'}
                  </div>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* 4. Sectors We Serve */}
      <section className="py-24 bg-gray-900 text-white relative overflow-hidden group/sector-section">
        <div className="absolute inset-0 pointer-events-none opacity-[0.03]" style={{ backgroundImage: 'linear-gradient(#ffffff 1px, transparent 1px), linear-gradient(90deg, #ffffff 1px, transparent 1px)', backgroundSize: '50px 50px' }}></div>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <Reveal>
            <div className="mb-12 flex items-end justify-between border-b border-white/10 pb-6">
              <div>
                <h2 className="text-4xl font-bold text-white">Sectors We Serve</h2>
                <p className="text-yellow-500 mt-2 font-mono text-sm tracking-widest">ENGINEERING CAPABILITIES // EST. 1996</p>
              </div>
              <Crosshair className="w-4 h-4 text-yellow-500" style={{ animation: 'spin 8s linear infinite' }} />
            </div>
          </Reveal>

          <div className="grid lg:grid-cols-12 gap-12">
            <div className="lg:col-span-5 flex flex-col">
              {sectorsData.map((sector, index) => (
                <div
                  key={index}
                  onMouseEnter={() => setActiveSector(sector)}
                  onClick={() => navigate(`/projects?category=${encodeURIComponent(sector.title)}&view=list`)}
                  className={`group relative flex items-center justify-between py-5 border-b border-white/10 cursor-pointer transition-all duration-300 ${activeSector.id === sector.id ? 'pl-4 border-yellow-500 bg-white/5' : 'hover:pl-4 hover:border-yellow-500/50'}`}
                >
                  <div className="flex flex-col">
                    <div className="flex items-center gap-3">
                      <span className={`text-xs font-mono transition-colors ${activeSector.id === sector.id ? 'text-yellow-500' : 'text-slate-500'}`}>{sector.id}</span>
                      <span className={`text-xl font-medium transition-colors ${activeSector.id === sector.id ? 'text-white' : 'text-gray-300 group-hover:text-white'}`}>{sector.title}</span>
                    </div>
                  </div>
                  <ArrowUpRight className={`w-5 h-5 transition-all duration-300 ${activeSector.id === sector.id ? 'text-yellow-500 translate-x-0 opacity-100' : 'text-slate-600 opacity-0'}`} />
                </div>
              ))}
            </div>

            <Reveal direction="right" className="lg:col-span-7 relative h-[500px] hidden lg:block lg:sticky lg:top-24 group/image-container">
              <div className="w-full h-full relative rounded-sm overflow-hidden border border-white/10 bg-black">
                <AnimatePresence mode="wait">
                  <motion.div
                    key={activeSector.id}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="relative w-full h-full"
                  >
                    {/* BLUEPRINT (DEFAULT VIEW) */}
                    <img
                      src={activeSector.sketch}
                      alt={`${activeSector.title} blueprint`}
                      className="absolute inset-0 w-full h-full object-cover transition-opacity duration-700 opacity-100 group-hover/image-container:opacity-0"
                      style={{ zIndex: 10 }}
                    />

                    {/* REAL IMAGE (REVEALED ON HOVER) */}
                    <img
                      src={activeSector.img}
                      alt={activeSector.title}
                      className="absolute inset-0 w-full h-full object-cover transition-opacity duration-700 opacity-0 group-hover/image-container:opacity-100"
                      style={{ zIndex: 5 }}
                    />
                  </motion.div>
                </AnimatePresence>

                <div className="absolute bottom-0 left-0 w-full bg-gradient-to-t from-gray-900 pt-20 pb-8 px-8 z-20">
                  <div className="border-l-2 border-yellow-500 pl-6">
                    <h3 className="text-3xl font-bold text-white mb-2">{activeSector.title}</h3>
                    <p className="text-gray-300 max-w-md">{activeSector.desc}</p>
                  </div>
                </div>
              </div>
            </Reveal>
          </div>
        </div>
      </section>

      {/* 5. Engineering Service Suite */}
      <section className="py-32 bg-slate-900 relative overflow-hidden border-t border-white/10">
        <div className="absolute inset-0 pointer-events-none opacity-[0.05]" style={{ backgroundImage: 'linear-gradient(#EAB308 1px, transparent 1px), linear-gradient(90deg, #EAB308 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="flex flex-col md:flex-row md:items-end justify-between mb-20 gap-6">
            <div>
              <div className="flex items-center gap-2 mb-4">
                <Cpu className="w-5 h-5 text-yellow-500" />
                <span className="text-yellow-500 font-mono text-sm tracking-widest uppercase">Technical Capabilities</span>
              </div>
              <h2 className="text-4xl md:text-5xl font-bold text-white leading-tight">Engineering <br /><span className="text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-500">Service Suite</span></h2>
            </div>

            <Reveal direction="left">
              <Link
                to="/services"
                className="group flex items-center gap-2 px-6 py-3 bg-yellow-500/10 text-yellow-500 border border-yellow-500/50 hover:bg-yellow-500 hover:text-slate-900 font-bold uppercase tracking-widest text-sm rounded-sm transition-all shadow-[0_0_15px_rgba(234,179,8,0.15)] hover:shadow-[0_0_25px_rgba(234,179,8,0.4)]"
              >
                Learn More
                <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
              </Link>
            </Reveal>
          </div>
          <div className="grid md:grid-cols-3 gap-6">
            {servicesData.map((item, index) => (
              <Reveal key={index} delay={index === 1 ? 'delay-100' : index === 2 ? 'delay-200' : ''}>
                <div className="group relative h-full bg-slate-800/30 backdrop-blur-sm border border-white/10 p-8 hover:bg-slate-800/80 transition-all duration-500 hover:-translate-y-2 overflow-hidden rounded-sm">
                  <div className="absolute top-0 left-0 w-4 h-4 border-t border-l border-white/20 group-hover:border-yellow-500 transition-colors" />
                  <div className="absolute bottom-0 right-0 w-4 h-4 border-b border-r border-white/20 group-hover:border-yellow-500 transition-colors" />
                  <h3 className="text-xl font-bold text-white mb-4 group-hover:text-yellow-500 transition-colors">{item.title}</h3>
                  <p className="text-gray-400 text-sm leading-relaxed mb-4">{item.desc}</p>
                </div>
              </Reveal>
            ))}
          </div>
        </div>
      </section>

      <Footer />

      <style>{`
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @keyframes slide-up { from { opacity: 0; transform: translateY(30px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes slide-in-left { from { opacity: 0; transform: translateX(-60px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes slide-in-right { from { opacity: 0; transform: translateX(60px); } to { opacity: 1; transform: translateX(0); } }
        @keyframes fade-in-up { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fade-in-up { animation: fade-in-up 0.5s ease-out forwards; }
        .animate-slide-up { animation: slide-up 0.8s ease-out forwards; }
        .animate-slide-in-left { animation: slide-in-left 1s ease-out forwards; }
        .animate-slide-in-right { animation: slide-in-right 1s ease-out forwards; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #0f172a; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #EAB308; }
      `}</style>
    </div>
  );
}
